// ENGLISH
const englishQuestions = [
  { id: 'eng31', year: 2024, topic: 'Lexis & Structure', difficulty: 'easy', question: '"She has been suffering _____ malaria for two weeks." Choose the correct preposition.', options: ['A: from', 'B: with', 'C: by', 'D: of'], answer: 'A', explanation: 'The correct expression is "suffering from" when referring to an illness or disease.' },
  { id: 'eng32', year: 2024, topic: 'Comprehension', difficulty: 'medium', question: 'The writer describes the sunset as "a golden cascade spilling across the horizon." This is an example of:', options: ['A: Simile', 'B: Metaphor', 'C: Personification', 'D: Hyperbole'], answer: 'B', explanation: 'A metaphor is a direct comparison without "like" or "as". The sunset is directly described as a golden cascade.' },
  { id: 'eng33', year: 2024, topic: 'Oral English', difficulty: 'hard', question: 'Which word has the /tS/ (ch) sound?', options: ['A: machine', 'B: chef', 'C: church', 'D: champagne'], answer: 'C', explanation: '"Church" has the /tS/ sound. "Machine", "chef", and "champagne" all have the /S/ (sh) sound.' },
  { id: 'eng34', year: 2024, topic: 'Proverbs & Idioms', difficulty: 'medium', question: '"Every cloud has a silver lining" means:', options: ['A: Clouds are lined with silver', 'B: There is hope even in difficult situations', 'C: Rain brings wealth', 'D: Silver is found in clouds'], answer: 'B', explanation: 'This proverb means that every difficult or unpleasant situation has some positive aspect.' },
  { id: 'eng35', year: 2024, topic: 'Antonyms & Synonyms', difficulty: 'easy', question: 'Choose the synonym of "ALLEVIATE".', options: ['A: Worsen', 'B: Relieve', 'C: Increase', 'D: Intensify'], answer: 'B', explanation: '"Alleviate" means to make suffering or a problem less severe. "Relieve" is its synonym.' },
  { id: 'eng36', year: 2024, topic: 'Sentence Interpretation', difficulty: 'medium', question: '"He always keeps his cards close to his chest." This means he:', options: ['A: Is a gambler', 'B: Is secretive about his plans', 'C: Loses at cards', 'D: Plays fairly'], answer: 'B', explanation: '"To keep one\'s cards close to one\'s chest" means to be secretive or not reveal one\'s intentions.' },
  { id: 'eng37', year: 2024, topic: 'Cloze Passages', difficulty: 'hard', question: '"The governor _____ the new hospital last week."', options: ['A: commissioned', 'B: commented', 'C: commenced', 'D: commanded'], answer: 'A', explanation: '"Commissioned" means formally opening or putting into service, which fits the context of a new hospital.' },
  { id: 'eng38', year: 2023, topic: 'Register', difficulty: 'medium', question: 'In economics, "inflation" refers to:', options: ['A: Increase in employment', 'B: General rise in prices', 'C: Decrease in taxes', 'D: Growth in GDP'], answer: 'B', explanation: 'Inflation is the sustained increase in the general price level of goods and services in an economy.' },
  { id: 'eng39', year: 2023, topic: 'Stress & Intonation', difficulty: 'hard', question: 'Which syllable is stressed in "understand"?', options: ['A: First', 'B: Second', 'C: Third', 'D: First and third'], answer: 'C', explanation: '"Understand" (un-der-STAND) has primary stress on the third syllable.' },
  { id: 'eng40', year: 2023, topic: 'Lexis & Structure', difficulty: 'easy', question: '"They have been living here _____ 2015."', options: ['A: since', 'B: for', 'C: from', 'D: in'], answer: 'A', explanation: '"Since" is used with a specific point in time (2015). "For" is used with a duration.' },
  { id: 'eng41', year: 2023, topic: 'Comprehension', difficulty: 'medium', question: 'Read: "The torrential rain caused widespread flooding, displacing thousands." The word "displacing" means:', options: ['A: Destroying', 'B: Forcing to leave', 'C: Annoying', 'D: Replacing'], answer: 'B', explanation: '"Displacing" in this context means forcing people to leave their homes due to the flooding.' },
  { id: 'eng42', year: 2023, topic: 'Oral English', difficulty: 'medium', question: 'Which word has the /aI/ diphthong?', options: ['A: boy', 'B: cow', 'C: time', 'D: toy'], answer: 'C', explanation: '"Time" has the /aI/ diphthong (as in "eye"). "Boy" and "toy" have /OI/, "cow" has /aU/.' },
  { id: 'eng43', year: 2023, topic: 'Proverbs & Idioms', difficulty: 'medium', question: '"Rome was not built in a day" means:', options: ['A: Romans were slow builders', 'B: Great achievements take time', 'C: Rome is very old', 'D: Building requires many people'], answer: 'B', explanation: 'This proverb teaches that complex or great achievements require time and patience.' },
  { id: 'eng44', year: 2023, topic: 'Antonyms & Synonyms', difficulty: 'easy', question: 'Choose the antonym of "ELABORATE".', options: ['A: Detailed', 'B: Simple', 'C: Complex', 'D: Ornate'], answer: 'B', explanation: '"Elaborate" means involving many details or complicated. Its opposite is "simple".' },
  { id: 'eng45', year: 2023, topic: 'Sentence Interpretation', difficulty: 'medium', question: '"Were I the president, I would reduce taxes." This expresses:', options: ['A: A past event', 'B: An unreal present condition', 'C: A future plan', 'D: A command'], answer: 'B', explanation: 'This is a subjunctive mood expressing an unreal or hypothetical present situation.' },
  { id: 'eng46', year: 2023, topic: 'Cloze Passages', difficulty: 'hard', question: '"The court _____ the defendant of all charges." Correct word:', options: ['A: acquitted', 'B: convicted', 'C: accused', 'D: summoned'], answer: 'A', explanation: '"Acquitted" means officially declaring someone not guilty of a criminal charge.' },
  { id: 'eng47', year: 2023, topic: 'Register', difficulty: 'medium', question: 'In computing, "malware" refers to:', options: ['A: A type of hardware', 'B: Malicious software', 'C: A programming language', 'D: A network cable'], answer: 'B', explanation: '"Malware" is a portmanteau of "malicious" and "software", referring to programs designed to cause harm.' },
  { id: 'eng48', year: 2022, topic: 'Stress & Intonation', difficulty: 'hard', question: 'In "demonstration", which syllable has the primary stress?', options: ['A: First', 'B: Second', 'C: Third', 'D: Fourth'], answer: 'C', explanation: '"Demonstration" (dem-on-STRA-tion) has primary stress on the third syllable.' },
  { id: 'eng49', year: 2022, topic: 'Lexis & Structure', difficulty: 'easy', question: '"Not only did she pass the exam, _____ she topped the class."', options: ['A: but', 'B: and', 'C: also', 'D: so'], answer: 'C', explanation: 'The correct correlative structure is "not only...but also". "Also" completes the expression.' },
  { id: 'eng50', year: 2022, topic: 'Comprehension', difficulty: 'medium', question: 'The passage states: "Education is the bedrock of any progressive society." This implies:', options: ['A: Education is expensive', 'B: Society rests on education', 'C: Only the educated can progress', 'D: Schools are buildings'], answer: 'B', explanation: '"Bedrock" is a metaphor meaning the solid foundation. Education is the foundation of societal progress.' },
  { id: 'eng51', year: 2022, topic: 'Oral English', difficulty: 'hard', question: 'Which word has a silent letter?', options: ['A: often', 'B: castle', 'C: listen', 'D: All of the above'], answer: 'D', explanation: '"Often" (silent t), "castle" (silent t), and "listen" (silent t) all contain silent letters.' },
  { id: 'eng52', year: 2022, topic: 'Proverbs & Idioms', difficulty: 'easy', question: '"To kill two birds with one stone" means:', options: ['A: To hunt efficiently', 'B: To achieve two goals with one action', 'C: To hurt animals', 'D: To waste effort'], answer: 'B', explanation: 'This idiom means accomplishing two objectives with a single action or effort.' },
  { id: 'eng53', year: 2022, topic: 'Antonyms & Synonyms', difficulty: 'medium', question: 'Choose the antonym of "FRUGAL".', options: ['A: Economical', 'B: Extravagant', 'C: Thrifty', 'D: Careful'], answer: 'B', explanation: '"Frugal" means sparing or economical with money. "Extravagant" (spending freely) is its antonym.' },
  { id: 'eng54', year: 2022, topic: 'Sentence Interpretation', difficulty: 'medium', question: '"By the time we arrived, the train had already left." This indicates:', options: ['A: A future event', 'B: An action completed before another past action', 'C: A simultaneous action', 'D: A habitual action'], answer: 'B', explanation: 'The past perfect "had left" shows an action completed before another past action (arriving).' },
  { id: 'eng55', year: 2022, topic: 'Cloze Passages', difficulty: 'medium', question: '"The marketing team _____ a new strategy to boost sales."', options: ['A: devised', 'B: devoured', 'C: diverged', 'D: diverted'], answer: 'A', explanation: '"Devised" means planned or invented a strategy. The other words have different meanings.' },
  { id: 'eng56', year: 2022, topic: 'Register', difficulty: 'medium', question: 'In education, "curriculum" refers to:', options: ['A: A building', 'B: The subjects and course content', 'C: A teaching method', 'D: A type of exam'], answer: 'B', explanation: 'Curriculum refers to the subjects, content, and learning experiences offered by an educational institution.' },
  { id: 'eng57', year: 2022, topic: 'Stress & Intonation', difficulty: 'hard', question: 'Which word is stressed on the FIRST syllable?', options: ['A: believe', 'B: comfort', 'C: prepare', 'D: repeat'], answer: 'B', explanation: '"Comfort" (COM-fort) has first-syllable stress. The others are stressed on the second syllable.' },
  { id: 'eng58', year: 2021, topic: 'Lexis & Structure', difficulty: 'easy', question: '"Would you mind _____ the window?"', options: ['A: open', 'B: opened', 'C: opening', 'D: to open'], answer: 'C', explanation: 'The phrase "would you mind" is followed by a gerund (-ing form): "Would you mind opening...".' },
  { id: 'eng59', year: 2021, topic: 'Comprehension', difficulty: 'medium', question: '"The author\'s tone in the passage can best be described as nostalgic." Nostalgic means:', options: ['A: Angry', 'B: Longing for the past', 'C: Fearful', 'D: Indifferent'], answer: 'B', explanation: '"Nostalgic" refers to a sentimental longing or affection for the past.' },
  { id: 'eng60', year: 2021, topic: 'Oral English', difficulty: 'medium', question: 'Which word has the /3:/ (long vowel) sound like in "turn"?', options: ['A: burn', 'B: born', 'C: barn', 'D: bean'], answer: 'A', explanation: '"Burn" has the /3:/ sound. "Born" has /O:/, "barn" has /a:/, and "bean" has /i:/.' },
  { id: 'eng61', year: 2021, topic: 'Proverbs & Idioms', difficulty: 'medium', question: '"When in Rome, do as the Romans do" means:', options: ['A: Romans are the best', 'B: Adapt to local customs when visiting', 'C: Rome has many rules', 'D: Travel is important'], answer: 'B', explanation: 'This proverb advises visitors to follow the customs and practices of the people in a place they are visiting.' },
  { id: 'eng62', year: 2021, topic: 'Antonyms & Synonyms', difficulty: 'medium', question: 'Choose the synonym of "AUTHENTIC".', options: ['A: Fake', 'B: Genuine', 'C: Artificial', 'D: False'], answer: 'B', explanation: '"Authentic" means real, genuine, or not counterfeit. "Genuine" is its direct synonym.' },
  { id: 'eng63', year: 2021, topic: 'Sentence Interpretation', difficulty: 'hard', question: '"It is high time we left." This means:', options: ['A: The time is high', 'B: We should have left already', 'C: We are early', 'D: The time is not yet right'], answer: 'B', explanation: '"It is high time" is an expression suggesting something should have been done already and is overdue.' },
  { id: 'eng64', year: 2021, topic: 'Cloze Passages', difficulty: 'hard', question: '"The investigation will _____ the truth behind the allegations."', options: ['A: unveil', 'B: unload', 'C: unlock', 'D: unfold'], answer: 'A', explanation: '"Unveil" means to reveal or make known, which fits the context of revealing the truth.' },
  { id: 'eng65', year: 2021, topic: 'Register', difficulty: 'easy', question: 'In banking, "overdraft" means:', options: ['A: Depositing money', 'B: Withdrawing more than the account balance', 'C: Closing an account', 'D: Opening an account'], answer: 'B', explanation: 'An overdraft occurs when withdrawals exceed the available balance in a bank account.' },
  { id: 'eng66', year: 2021, topic: 'Lexis & Structure', difficulty: 'medium', question: 'Choose the correct sentence:', options: ['A: The committee have submitted its report', 'B: The committee has submitted its report', 'C: The committee has submitted their report', 'D: The committee have submitted their report'], answer: 'B', explanation: '"Committee" is a collective noun treated as singular in British English, so it takes "has" and "its".' },
  { id: 'eng67', year: 2020, topic: 'Comprehension', difficulty: 'medium', question: '"The passage suggests that technology has both positive and negative effects." This is a:', options: ['A: One-sided argument', 'B: Balanced view', 'C: Biased opinion', 'D: False claim'], answer: 'B', explanation: 'Acknowledging both positive and negative aspects presents a balanced view of the topic.' },
  { id: 'eng68', year: 2020, topic: 'Oral English', difficulty: 'hard', question: 'Which word has a different number of syllables?', options: ['A: education', 'B: information', 'C: communication', 'D: foundation'], answer: 'D', explanation: '"Foundation" has 3 syllables (foun-da-tion). The others have 4 syllables each.' },
  { id: 'eng69', year: 2020, topic: 'Proverbs & Idioms', difficulty: 'medium', question: '"A rolling stone gathers no moss" means:', options: ['A: Stones roll downhill', 'B: Constant movement prevents accumulation', 'C: Moss grows on stones', 'D: Rolling is good for stones'], answer: 'B', explanation: 'This proverb means a person who keeps moving and never settles does not build lasting relationships or wealth.' },
  { id: 'eng70', year: 2020, topic: 'Antonyms & Synonyms', difficulty: 'hard', question: 'Opposite of "PRAGMATIC".', options: ['A: Practical', 'B: Idealistic', 'C: Realistic', 'D: Rational'], answer: 'B', explanation: '"Pragmatic" means dealing with things practically. "Idealistic" (based on ideals rather than practicality) is the antonym.' },
  { id: 'eng71', year: 2020, topic: 'Sentence Interpretation', difficulty: 'medium', question: '"I wish I knew the answer." This expresses:', options: ['A: A past regret', 'B: A present desire', 'C: A future hope', 'D: A question'], answer: 'B', explanation: '"I wish" followed by past tense expresses a desire about an unreal present situation.' },
  { id: 'eng72', year: 2020, topic: 'Lexis & Structure', difficulty: 'hard', question: '"The proposal, _____ was submitted yesterday, has been approved." Correct relative pronoun:', options: ['A: who', 'B: which', 'C: whom', 'D: whose'], answer: 'B', explanation: '"Which" refers to things (the proposal). "Who/whom" refer to people.' },
  { id: 'eng73', year: 2020, topic: 'Stress & Intonation', difficulty: 'hard', question: 'In "biology", which syllable is stressed?', options: ['A: First', 'B: Second', 'C: Third', 'D: Fourth'], answer: 'B', explanation: '"Biology" (bi-OL-o-gy) has primary stress on the second syllable.' },
  { id: 'eng74', year: 2024, topic: 'Passage Analysis', difficulty: 'medium', question: 'In a passage, the writer uses short, abrupt sentences to create a sense of urgency. This style is called:', options: ['A: Euphuism', 'B: Telegraphic style', 'C: Bombastic style', 'D: Circumlocution'], answer: 'B', explanation: 'Telegraphic style uses short, direct sentences for impact or urgency, avoiding unnecessary words.' },
  { id: 'eng75', year: 2024, topic: 'Passage Analysis', difficulty: 'hard', question: 'A passage that argues "all political power derives from the people" primarily employs which rhetorical appeal?', options: ['A: Ethos', 'B: Pathos', 'C: Logos', 'D: Kairos'], answer: 'A', explanation: 'Ethos appeals to credibility, authority, or shared values. This statement appeals to democratic principles (ethos).' },
  { id: 'eng76', year: 2023, topic: 'Passage Analysis', difficulty: 'medium', question: 'Read: "The old man\'s hands trembled as he clutched the faded photograph. Tears welled in his eyes." The dominant mood is:', options: ['A: Joyful', 'B: Melancholic', 'C: Humorous', 'D: Suspenseful'], answer: 'B', explanation: 'The description of trembling hands and tears creates a melancholic (sad and reflective) mood.' },
  { id: 'eng77', year: 2023, topic: 'Passage Analysis', difficulty: 'medium', question: '"The river snaked through the valley like a silver ribbon." The device used is:', options: ['A: Simile and metaphor', 'B: Simile only', 'C: Metaphor only', 'D: Personification'], answer: 'A', explanation: '"Snaked" is a metaphor (river moves like a snake), and "like a silver ribbon" is a simile using "like".' },
  { id: 'eng78', year: 2022, topic: 'Passage Analysis', difficulty: 'hard', question: 'A passage begins with a rhetorical question: "What is the purpose of education if not to liberate the mind?" This technique aims to:', options: ['A: Confuse the reader', 'B: Engage and provoke thought', 'C: Provide an answer', 'D: Summarize the text'], answer: 'B', explanation: 'Rhetorical questions engage readers and provoke critical thinking without expecting a direct answer.' },
  { id: 'eng79', year: 2024, topic: 'Phonetics', difficulty: 'easy', question: 'The /p/ sound in "pin" and the /b/ sound in "bin" are distinguished by:', options: ['A: Voicing', 'B: Place of articulation', 'C: Manner of articulation', 'D: Nasality'], answer: 'A', explanation: '/p/ is voiceless and /b/ is voiced. Both are bilabial plosives, differing only in voicing.' },
  { id: 'eng80', year: 2024, topic: 'Phonetics', difficulty: 'medium', question: 'How many consonant sounds are in the word "strength"?', options: ['A: 5', 'B: 6', 'C: 7', 'D: 8'], answer: 'C', explanation: '"Strength" = /strEngTH/ has 7 consonant sounds and 1 vowel sound. Consonants: s,t,r,N,g,TH.' },
  { id: 'eng81', year: 2023, topic: 'Phonetics', difficulty: 'medium', question: 'Which of the following is a voiced fricative?', options: ['A: /f/', 'B: /s/', 'C: /v/', 'D: /S/'], answer: 'C', explanation: '/v/ is a voiced labiodental fricative. /f/ and /s/ are voiceless, and /S/ (sh) is also voiceless.' },
  { id: 'eng82', year: 2023, topic: 'Phonetics', difficulty: 'hard', question: 'The initial sound in "judge" is a:', options: ['A: Voiceless affricate', 'B: Voiced affricate', 'C: Voiceless fricative', 'D: Voiced plosive'], answer: 'B', explanation: 'The /dZ/ sound in "judge" is a voiced palato-alveolar affricate.' },
  { id: 'eng83', year: 2022, topic: 'Phonetics', difficulty: 'hard', question: 'Which set has all nasal consonant sounds?', options: ['A: /m, n, N/', 'B: /b, d, g/', 'C: /p, t, k/', 'D: /f, s, S/'], answer: 'A', explanation: '/m/, /n/, and /N/ (ng) are all nasal consonants. Air passes through the nose when producing them.' },
  { id: 'eng84', year: 2024, topic: 'Spelling', difficulty: 'easy', question: 'Which is correctly spelled?', options: ['A: Recieve', 'B: Receive', 'C: Recive', 'D: Receeve'], answer: 'B', explanation: 'The correct spelling is "receive" following the "i before e except after c" rule.' },
  { id: 'eng85', year: 2023, topic: 'Spelling', difficulty: 'medium', question: 'Choose the correct spelling:', options: ['A: Embarrass', 'B: Embarass', 'C: Embarras', 'D: Embaras'], answer: 'A', explanation: '"Embarrass" is spelled with two r\'s and two s\'s.' },
  { id: 'eng86', year: 2023, topic: 'Spelling', difficulty: 'medium', question: 'Which is correctly spelled?', options: ['A: Occassion', 'B: Ocassion', 'C: Occasion', 'D: Ocasion'], answer: 'C', explanation: '"Occasion" is spelled with double c and single s.' },
  { id: 'eng87', year: 2022, topic: 'Spelling', difficulty: 'hard', question: 'Correct spelling of the word meaning "a person who illegally enters a building to steal":', options: ['A: Burgler', 'B: Burgalar', 'C: Burglar', 'D: Burglair'], answer: 'C', explanation: 'The correct spelling is "burglar". "Burglary" is the crime.' },
  { id: 'eng88', year: 2024, topic: 'Literature', difficulty: 'medium', question: 'In literature, "the struggle between two opposing forces" is called:', options: ['A: Plot', 'B: Conflict', 'C: Theme', 'D: Setting'], answer: 'B', explanation: 'Conflict is the central struggle or clash between opposing forces in a literary work.' },
  { id: 'eng89', year: 2024, topic: 'Literature', difficulty: 'medium', question: '"The main character in a literary work" is called the:', options: ['A: Antagonist', 'B: Protagonist', 'C: Narrator', 'D: Foil'], answer: 'B', explanation: 'The protagonist is the main character around whom the story revolves.' },
  { id: 'eng90', year: 2023, topic: 'Literature', difficulty: 'hard', question: 'A literary device where the audience knows something the characters do not is:', options: ['A: Dramatic irony', 'B: Situational irony', 'C: Verbal irony', 'D: Sarcasm'], answer: 'A', explanation: 'Dramatic irony occurs when the audience has knowledge that the characters in the story lack.' },
  { id: 'eng91', year: 2022, topic: 'Literature', difficulty: 'medium', question: '"A short story with a moral lesson, often featuring animals as characters" is a:', options: ['A: Novel', 'B: Fable', 'C: Biography', 'D: Play'], answer: 'B', explanation: 'A fable is a short story, typically with animals, that conveys a moral lesson.' },
  { id: 'eng92', year: 2021, topic: 'Lexis & Structure', difficulty: 'medium', question: '"The children were told to _____ their books and listen."', options: ['A: put away', 'B: put off', 'C: put on', 'D: put up'], answer: 'A', explanation: '"Put away" means to place something in its proper place or out of sight.' },
  { id: 'eng93', year: 2021, topic: 'Comprehension', difficulty: 'hard', question: '"The writer uses statistics and data to support the argument." This appeal is primarily:', options: ['A: Ethical', 'B: Emotional', 'C: Logical', 'D: Political'], answer: 'C', explanation: 'Using statistics and data appeals to logos, the logical appeal based on reason and evidence.' },
  { id: 'eng94', year: 2020, topic: 'Oral English', difficulty: 'medium', question: 'Which word is pronounced differently in terms of the initial sound?', options: ['A: psychology', 'B: pneumonia', 'C: psalm', 'D: peach'], answer: 'D', explanation: '"Peach" starts with the /p/ sound. The others have a silent "p" at the beginning.' },
  { id: 'eng95', year: 2020, topic: 'Proverbs & Idioms', difficulty: 'medium', question: '"The pen is mightier than the sword" means:', options: ['A: Writing is violent', 'B: Written communication is more powerful than force', 'C: Pens are weapons', 'D: Swords are weak'], answer: 'B', explanation: 'This proverb means that writing, ideas, and communication have more lasting impact than violence.' },
  { id: 'eng96', year: 2020, topic: 'Antonyms & Synonyms', difficulty: 'medium', question: 'Synonym of "MUNDANE".', options: ['A: Extraordinary', 'B: Ordinary', 'C: Rare', 'D: Unique'], answer: 'B', explanation: '"Mundane" means lacking interest or excitement; ordinary. "Extraordinary" is its antonym.' },
  { id: 'eng97', year: 2020, topic: 'Sentence Interpretation', difficulty: 'hard', question: '"Not until the referee blows the whistle will the match begin." This means:', options: ['A: The match begins before the whistle', 'B: The match begins only after the whistle', 'C: The whistle is blown after the match', 'D: The match begins during the whistle'], answer: 'B', explanation: '"Not until" indicates the match will not start before the whistle. The whistle is a prerequisite.' },
  { id: 'eng98', year: 2021, topic: 'Register', difficulty: 'easy', question: 'In religion, "gospel" refers to:', options: ['A: A type of music', 'B: The teachings of Christ', 'C: A church building', 'D: A religious leader'], answer: 'B', explanation: 'The Gospel refers to the teachings and life of Jesus Christ as recorded in the New Testament.' },
  { id: 'eng99', year: 2021, topic: 'Lexis & Structure', difficulty: 'hard', question: '"The team _____ playing well this season." Correct verb form:', options: ['A: is', 'B: are', 'C: has been', 'D: was'], answer: 'B', explanation: 'In British English, collective nouns like "team" can take plural verbs when emphasizing individual members.' },
  { id: 'eng100', year: 2020, topic: 'Cloze Passages', difficulty: 'medium', question: '"The _____ of the new policy was met with mixed reactions from the public."', options: ['A: introduction', 'B: introspection', 'C: intrusion', 'D: intuition'], answer: 'A', explanation: '"Introduction" (the act of bringing in something new) fits the context of a new policy.' },
  { id: 'eng101', year: 2024, topic: 'Passage Analysis', difficulty: 'medium', question: 'A passage contains the line: "His voice was thunder, his eyes lightning." This uses:', options: ['A: Simile', 'B: Metaphor', 'C: Alliteration', 'D: Onomatopoeia'], answer: 'B', explanation: 'The direct comparison of voice to thunder and eyes to lightning without "like" or "as" is a metaphor.' },
  { id: 'eng102', year: 2023, topic: 'Phonetics', difficulty: 'easy', question: 'The phonetic symbol /D/ represents the sound in:', options: ['A: thin', 'B: this', 'C: think', 'D: thumb'], answer: 'B', explanation: '/D/ (voiced th) is found in "this", "that", "those". /T/ (voiceless th) is in "thin", "think", "thumb".' },
  { id: 'eng103', year: 2022, topic: 'Spelling', difficulty: 'medium', question: 'Correct spelling meaning "not relevant":', options: ['A: Irrelevent', 'B: Irrelevant', 'C: Irrevelant', 'D: Irrevalent'], answer: 'B', explanation: 'The correct spelling is "irrelevant" (ir- + relevant).' },
  { id: 'eng104', year: 2021, topic: 'Literature', difficulty: 'hard', question: 'A literary work that exposes societal flaws through humor and ridicule is a:', options: ['A: Comedy', 'B: Satire', 'C: Tragedy', 'D: Romance'], answer: 'B', explanation: 'Satire uses humor, irony, and exaggeration to criticize and expose societal problems or vices.' },
  { id: 'eng105', year: 2020, topic: 'Stress & Intonation', difficulty: 'hard', question: 'In which pair do both words have the same stress pattern?', options: ['A: PHOtograph / phoTOGraphy', 'B: ECOlogy / ecoLOgical', 'C: COMfort / comFORtable', 'D: NAtion / naTIONal'], answer: 'B', explanation: '"Ecology" stresses the second syllable; "ecological" also stresses the second syllable (e-CO-logy / e-co-LO-gical).' }
]

// MATHEMATICS
const mathematicsQuestions = [
  { id: 'math26', year: 2024, topic: 'Algebra', difficulty: 'easy', question: 'Simplify: 3a + 2b - a + 4b', options: ['A: 2a + 6b', 'B: 4a + 6b', 'C: 2a + 2b', 'D: 4a + 2b'], answer: 'A', explanation: '3a - a = 2a, 2b + 4b = 6b. Result: 2a + 6b.' },
  { id: 'math27', year: 2024, topic: 'Geometry', difficulty: 'medium', question: 'A rectangle length = 12 cm, width = 5 cm. Diagonal length?', options: ['A: 13 cm', 'B: 14 cm', 'C: 15 cm', 'D: 17 cm'], answer: 'A', explanation: 'Using Pythagoras: d^2 = 12^2 + 5^2 = 144 + 25 = 169, d = 13 cm.' },
  { id: 'math28', year: 2024, topic: 'Trigonometry', difficulty: 'hard', question: 'Given tan x = 4/3 and x is acute, find sin x.', options: ['A: 3/5', 'B: 4/5', 'C: 3/4', 'D: 5/4'], answer: 'B', explanation: 'tan x = opp/adj = 4/3, so hyp = 5 (3-4-5 triangle). sin x = opp/hyp = 4/5.' },
  { id: 'math29', year: 2024, topic: 'Statistics', difficulty: 'medium', question: 'Find the mode: 3, 5, 7, 5, 9, 5, 3, 7.', options: ['A: 3', 'B: 5', 'C: 7', 'D: 9'], answer: 'B', explanation: 'The mode is the most frequent value. 5 appears three times, more than any other number.' },
  { id: 'math30', year: 2024, topic: 'Number Bases', difficulty: 'medium', question: 'Convert 34_5 (base 5) to base 10.', options: ['A: 17', 'B: 19', 'C: 21', 'D: 34'], answer: 'B', explanation: '34_5 = 3x5 + 4x1 = 15 + 4 = 19.' },
  { id: 'math31', year: 2024, topic: 'Sets', difficulty: 'easy', question: 'If n(A) = 10, n(B) = 7, and n(AnB) = 3, find n(AuB).', options: ['A: 10', 'B: 14', 'C: 17', 'D: 20'], answer: 'B', explanation: 'n(AuB) = n(A) + n(B) - n(AnB) = 10 + 7 - 3 = 14.' },
  { id: 'math32', year: 2024, topic: 'Probability', difficulty: 'medium', question: 'A bag contains 4 red, 5 white, and 3 blue balls. P(red or blue)?', options: ['A: 7/12', 'B: 1/3', 'C: 1/4', 'D: 5/12'], answer: 'A', explanation: 'Total = 12. Red or blue = 4 + 3 = 7. P = 7/12.' },
  { id: 'math33', year: 2024, topic: 'Surds', difficulty: 'hard', question: 'Rationalize: (2 + v3)/(2 - v3).', options: ['A: 7 + 4v3', 'B: 7 - 4v3', 'C: 1 + 4v3', 'D: 1 - 4v3'], answer: 'A', explanation: 'Multiply by conjugate: (2+v3)^2/(4-3) = (4+4v3+3)/1 = 7+4v3.' },
  { id: 'math34', year: 2024, topic: 'Matrices', difficulty: 'hard', question: 'Find the inverse of [[2,1],[5,3]].', options: ['A: [[3,-1],[-5,2]]', 'B: [[3,1],[5,2]]', 'C: [[-3,1],[5,-2]]', 'D: [[2,-1],[-5,3]]'], answer: 'A', explanation: 'det = 6-5 = 1. Inverse = (1/det) x [[3,-1],[-5,2]] = [[3,-1],[-5,2]].' },
  { id: 'math35', year: 2024, topic: 'Variation', difficulty: 'medium', question: 'y varies jointly as x and z. y = 48 when x = 4 and z = 3. Find y when x = 6 and z = 2.', options: ['A: 36', 'B: 48', 'C: 64', 'D: 72'], answer: 'B', explanation: 'y = kxz. k = 48/(4x3) = 4. y = 4x6x2 = 48.' },
  { id: 'math36', year: 2024, topic: 'Logarithms', difficulty: 'medium', question: 'Evaluate log_2 8 + log_2 4.', options: ['A: 3', 'B: 4', 'C: 5', 'D: 6'], answer: 'C', explanation: 'log_2 8 = 3 (2^3=8), log_2 4 = 2 (2^2=4). Sum = 5.' },
  { id: 'math37', year: 2024, topic: 'Mensuration', difficulty: 'easy', question: 'Area of a triangle with base 8 cm and height 6 cm.', options: ['A: 24 cm^2', 'B: 28 cm^2', 'C: 48 cm^2', 'D: 14 cm^2'], answer: 'A', explanation: 'Area = 1/2 x base x height = 1/2 x 8 x 6 = 24 cm^2.' },
  { id: 'math38', year: 2024, topic: 'Sequences & Series', difficulty: 'medium', question: 'Find the 10th term of AP: 3, 7, 11, 15...', options: ['A: 35', 'B: 39', 'C: 43', 'D: 47'], answer: 'B', explanation: 'a = 3, d = 4. T_n = a + (n-1)d. T_10 = 3 + 9x4 = 3 + 36 = 39.' },
  { id: 'math39', year: 2023, topic: 'Algebra', difficulty: 'medium', question: 'Solve: (x+2)/3 = (x-1)/4', options: ['A: x = -11', 'B: x = -5', 'C: x = 5', 'D: x = 11'], answer: 'A', explanation: '4(x+2) = 3(x-1), 4x+8 = 3x-3, x = -11.' },
  { id: 'math40', year: 2023, topic: 'Geometry', difficulty: 'medium', question: 'Angle sum of a pentagon?', options: ['A: 360', 'B: 450', 'C: 540', 'D: 720'], answer: 'C', explanation: 'Sum = (n-2)x180 = (5-2)x180 = 3x180 = 540 degrees.' },
  { id: 'math41', year: 2023, topic: 'Trigonometry', difficulty: 'medium', question: 'What is cos 60 degrees?', options: ['A: 0', 'B: 1/2', 'C: v3/2', 'D: 1'], answer: 'B', explanation: 'cos 60 = 0.5 = 1/2. This is a standard trigonometric value.' },
  { id: 'math42', year: 2023, topic: 'Statistics', difficulty: 'hard', question: 'Variance of {2, 4, 6, 8, 10}.', options: ['A: 6', 'B: 8', 'C: 10', 'D: 12'], answer: 'B', explanation: 'Mean = 6. Deviations: -4,-2,0,2,4. Squared: 16,4,0,4,16. Variance = (16+4+0+4+16)/5 = 40/5 = 8.' },
  { id: 'math43', year: 2023, topic: 'Number Bases', difficulty: 'medium', question: 'Convert 10101_2 to base 10.', options: ['A: 17', 'B: 21', 'C: 23', 'D: 25'], answer: 'B', explanation: '10101_2 = 16+0+4+0+1 = 21.' },
  { id: 'math44', year: 2023, topic: 'Sets', difficulty: 'medium', question: 'If A = {x: x is prime, x < 10} and B = {x: x is odd, x < 10}, find A u B.', options: ['A: {1,2,3,5,7,9}', 'B: {2,3,5,7}', 'C: {1,3,5,7,9}', 'D: {2,3,5,7,9}'], answer: 'A', explanation: 'A={2,3,5,7}, B={1,3,5,7,9}. A u B = {1,2,3,5,7,9}.' },
  { id: 'math45', year: 2023, topic: 'Probability', difficulty: 'medium', question: 'A card is drawn from a standard 52-card deck. P(heart)?', options: ['A: 1/52', 'B: 1/13', 'C: 1/4', 'D: 1/2'], answer: 'C', explanation: 'There are 13 hearts in a 52-card deck. P = 13/52 = 1/4.' },
  { id: 'math46', year: 2023, topic: 'Surds', difficulty: 'medium', question: 'Simplify: v12 + v27.', options: ['A: 3v3', 'B: 5v3', 'C: v39', 'D: 6v3'], answer: 'B', explanation: 'v12 = 2v3, v27 = 3v3. Sum = 5v3.' },
  { id: 'math47', year: 2023, topic: 'Matrices', difficulty: 'hard', question: 'Multiply: [[1,2],[3,4]] x [[5],[6]].', options: ['A: [[17],[39]]', 'B: [[11],[39]]', 'C: [[17],[29]]', 'D: [[7],[39]]'], answer: 'A', explanation: '[1x5+2x6, 3x5+4x6] = [5+12, 15+24] = [17, 39] as a column matrix.' },
  { id: 'math48', year: 2023, topic: 'Logarithms', difficulty: 'medium', question: 'Solve: log_10 x = 2.', options: ['A: 10', 'B: 20', 'C: 100', 'D: 200'], answer: 'C', explanation: 'log_10 x = 2 means x = 10^2 = 100.' },
  { id: 'math49', year: 2023, topic: 'Mensuration', difficulty: 'medium', question: 'Surface area of a cube with side 5 cm.', options: ['A: 125 cm^2', 'B: 150 cm^2', 'C: 100 cm^2', 'D: 175 cm^2'], answer: 'B', explanation: 'SA = 6s^2 = 6 x 25 = 150 cm^2.' },
  { id: 'math50', year: 2023, topic: 'Sequences & Series', difficulty: 'medium', question: 'Sum of first 5 terms of GP: 2, 6, 18, 54...', options: ['A: 242', 'B: 244', 'C: 484', 'D: 728'], answer: 'A', explanation: 'a=2, r=3. S_5 = 2(3^5-1)/(3-1) = 2(243-1)/2 = 242.' },
  { id: 'math51', year: 2022, topic: 'Algebra', difficulty: 'hard', question: 'Factorize: x^3 - 8.', options: ['A: (x-2)(x^2+2x+4)', 'B: (x+2)(x^2-2x+4)', 'C: (x-2)(x^2-2x+4)', 'D: (x+2)(x^2+2x+4)'], answer: 'A', explanation: 'Using difference of cubes: a^3 - b^3 = (a-b)(a^2+ab+b^2). Here x^3-2^3 = (x-2)(x^2+2x+4).' },
  { id: 'math52', year: 2022, topic: 'Geometry', difficulty: 'medium', question: 'Isosceles triangle, base angles each 70 degrees. Vertex angle?', options: ['A: 30', 'B: 40', 'C: 50', 'D: 55'], answer: 'B', explanation: 'Base angles equal: 70+70 = 140. Vertex = 180-140 = 40 degrees.' },
  { id: 'math53', year: 2022, topic: 'Trigonometry', difficulty: 'hard', question: 'If sin x = 0.6, find tan x (x acute).', options: ['A: 0.75', 'B: 0.8', 'C: 1.25', 'D: 0.6'], answer: 'A', explanation: 'sin x = 3/5, so opp=3, hyp=5, adj=4. tan x = opp/adj = 3/4 = 0.75.' },
  { id: 'math54', year: 2022, topic: 'Statistics', difficulty: 'easy', question: 'Find the median: 8, 12, 15, 9, 7, 10, 11.', options: ['A: 9', 'B: 10', 'C: 11', 'D: 12'], answer: 'B', explanation: 'Arrange: 7,8,9,10,11,12,15. Middle value (4th) = 10.' },
  { id: 'math55', year: 2022, topic: 'Number Bases', difficulty: 'hard', question: 'Convert 63_7 (base 7) to base 10.', options: ['A: 42', 'B: 45', 'C: 48', 'D: 51'], answer: 'B', explanation: '63_7 = 6x7 + 3x1 = 42 + 3 = 45.' },
  { id: 'math56', year: 2022, topic: 'Probability', difficulty: 'medium', question: 'Two coins tossed. P(at least one head)?', options: ['A: 1/4', 'B: 1/2', 'C: 3/4', 'D: 1'], answer: 'C', explanation: 'Outcomes: HH, HT, TH, TT. At least one head: 3/4.' },
  { id: 'math57', year: 2022, topic: 'Surds', difficulty: 'medium', question: 'Simplify: v8 x v2.', options: ['A: 2', 'B: 4', 'C: 8', 'D: 16'], answer: 'B', explanation: 'v8 x v2 = v(8x2) = v16 = 4.' },
  { id: 'math58', year: 2022, topic: 'Sets', difficulty: 'hard', question: 'In a class, 30 take Math, 20 take Physics, 10 take both. How many take at least one subject?', options: ['A: 30', 'B: 40', 'C: 50', 'D: 60'], answer: 'B', explanation: 'n(MuP) = n(M) + n(P) - n(MnP) = 30 + 20 - 10 = 40.' },
  { id: 'math59', year: 2022, topic: 'Matrices', difficulty: 'medium', question: 'If A = [[1,0],[0,1]], what is A^2?', options: ['A: [[1,0],[0,1]]', 'B: [[0,1],[1,0]]', 'C: [[1,1],[1,1]]', 'D: [[0,0],[0,0]]'], answer: 'A', explanation: 'A is the identity matrix. Any power of identity matrix is itself.' },
  { id: 'math60', year: 2022, topic: 'Variation', difficulty: 'easy', question: 'x varies directly as y. If x=10 when y=5, find x when y=8.', options: ['A: 12', 'B: 14', 'C: 16', 'D: 18'], answer: 'C', explanation: 'k = x/y = 10/5 = 2. x = 2 x 8 = 16.' },
  { id: 'math61', year: 2022, topic: 'Logarithms', difficulty: 'hard', question: 'If log_3 x = 4, find x.', options: ['A: 12', 'B: 27', 'C: 64', 'D: 81'], answer: 'D', explanation: 'log_3 x = 4, so x = 3^4 = 81.' },
  { id: 'math62', year: 2024, topic: 'Mensuration', difficulty: 'medium', question: 'Circumference of a circle is 44 cm. Find radius. (Pi = 22/7)', options: ['A: 7 cm', 'B: 10 cm', 'C: 14 cm', 'D: 21 cm'], answer: 'A', explanation: 'C = 2 pi r, 44 = 2 x (22/7) x r, r = (44x7)/(44) = 7 cm.' },
  { id: 'math63', year: 2024, topic: 'Sequences & Series', difficulty: 'hard', question: 'Sum of infinite GP: 1, 1/2, 1/4, 1/8...', options: ['A: 1', 'B: 1.5', 'C: 2', 'D: 3'], answer: 'C', explanation: 'Sum = a/(1-r) = 1/(1-1/2) = 1/(1/2) = 2.' },
  { id: 'math64', year: 2021, topic: 'Algebra', difficulty: 'easy', question: 'Solve: 5x - 3 = 2x + 9', options: ['A: 2', 'B: 4', 'C: 6', 'D: 8'], answer: 'B', explanation: '5x - 2x = 9 + 3, 3x = 12, x = 4.' },
  { id: 'math65', year: 2021, topic: 'Geometry', difficulty: 'hard', question: 'Chord 8 cm from center of circle radius 10 cm. Chord length?', options: ['A: 6 cm', 'B: 8 cm', 'C: 10 cm', 'D: 12 cm'], answer: 'D', explanation: 'Half chord = v(10^2 - 8^2) = v(100-64) = v36 = 6. Full chord = 12 cm.' },
  { id: 'math66', year: 2021, topic: 'Trigonometry', difficulty: 'easy', question: 'Value of sin 30 degrees?', options: ['A: 0', 'B: 1/2', 'C: v2/2', 'D: v3/2'], answer: 'B', explanation: 'sin 30 = 1/2. This is a fundamental trigonometric value.' },
  { id: 'math67', year: 2021, topic: 'Statistics', difficulty: 'medium', question: 'Standard deviation of {5, 5, 5, 5, 5} is:', options: ['A: 0', 'B: 5', 'C: 25', 'D: 1'], answer: 'A', explanation: 'All values are identical (mean=5). Deviations all zero, so standard deviation = 0.' },
  { id: 'math68', year: 2021, topic: 'Probability', difficulty: 'hard', question: 'A die is rolled twice. P(sum greater than 9)?', options: ['A: 1/6', 'B: 1/9', 'C: 1/12', 'D: 5/36'], answer: 'A', explanation: 'Favourable: (4,6),(5,5),(5,6),(6,4),(6,5),(6,6) = 6/36 = 1/6.' },
  { id: 'math69', year: 2021, topic: 'Algebra', difficulty: 'medium', question: 'Solve: x^2 - 5x + 6 = 0.', options: ['A: x=2 or x=3', 'B: x=-2 or x=-3', 'C: x=1 or x=6', 'D: x=-1 or x=-6'], answer: 'A', explanation: '(x-2)(x-3)=0, so x=2 or x=3.' },
  { id: 'math70', year: 2021, topic: 'Logarithms', difficulty: 'medium', question: 'Evaluate: log_10 1000.', options: ['A: 1', 'B: 2', 'C: 3', 'D: 4'], answer: 'C', explanation: 'log_10 1000 = log_10 10^3 = 3.' },
  { id: 'math71', year: 2021, topic: 'Mensuration', difficulty: 'hard', question: 'Volume of a sphere with radius 3 cm. (Pi = 3.14)', options: ['A: 84.78 cm^3', 'B: 113.04 cm^3', 'C: 37.68 cm^3', 'D: 56.52 cm^3'], answer: 'B', explanation: 'V = 4/3 pi r^3 = 4/3 x 3.14 x 27 = 4/3 x 84.78 = 113.04 cm^3.' },
  { id: 'math72', year: 2021, topic: 'Sequences & Series', difficulty: 'medium', question: 'Find the common difference of AP: 5, 9, 13, 17...', options: ['A: 3', 'B: 4', 'C: 5', 'D: 6'], answer: 'B', explanation: 'Common difference d = 9 - 5 = 4.' },
  { id: 'math73', year: 2020, topic: 'Algebra', difficulty: 'medium', question: 'Simplify: (2x^2 y^3)/(4xy^2).', options: ['A: xy/2', 'B: xy^2/2', 'C: x/2y', 'D: 2xy'], answer: 'A', explanation: '(2/4) x (x^2/x) x (y^3/y^2) = (1/2) x x x y = xy/2.' },
  { id: 'math74', year: 2020, topic: 'Geometry', difficulty: 'easy', question: 'Perimeter of a square with side 9 cm.', options: ['A: 18 cm', 'B: 27 cm', 'C: 36 cm', 'D: 81 cm'], answer: 'C', explanation: 'Perimeter = 4s = 4 x 9 = 36 cm.' },
  { id: 'math75', year: 2020, topic: 'Trigonometry', difficulty: 'medium', question: 'From a point 30 m from a building, angle of elevation to top is 60 degrees. Building height? (tan 60 = v3)', options: ['A: 30v3 m', 'B: 30 m', 'C: 15v3 m', 'D: 60 m'], answer: 'A', explanation: 'tan 60 = h/30, h = 30 tan 60 = 30v3 m.' },
  { id: 'math76', year: 2020, topic: 'Statistics', difficulty: 'hard', question: 'Find the interquartile range: 3, 6, 8, 10, 12, 15, 18.', options: ['A: 7', 'B: 9', 'C: 10', 'D: 12'], answer: 'B', explanation: 'Q1 = median of lower half = (6+8)/2 = 7. Q3 = median of upper half = (15+18)/2 = 16.5. IQR = 16.5 - 7 = 9.5, closest is 9.' },
  { id: 'math77', year: 2020, topic: 'Number Bases', difficulty: 'hard', question: 'Convert 124_5 to base 10.', options: ['A: 37', 'B: 39', 'C: 41', 'D: 43'], answer: 'B', explanation: '124_5 = 1x25 + 2x5 + 4x1 = 25 + 10 + 4 = 39.' },
  { id: 'math78', year: 2020, topic: 'Probability', difficulty: 'easy', question: 'Picking a vowel from the letters A-PROBABILITY. P(vowel)?', options: ['A: 4/11', 'B: 5/11', 'C: 6/11', 'D: 3/11'], answer: 'B', explanation: 'Letters: A,P,R,O,B,A,B,I,L,I,T,Y. Vowels: A,O,A,I,I (5). Total distinct: 11 letters. P = 5/11.' },
  { id: 'math79', year: 2020, topic: 'Surds', difficulty: 'hard', question: 'Simplify: (v3 + 1)(v3 - 1).', options: ['A: 2', 'B: 3', 'C: 4', 'D: v3'], answer: 'A', explanation: '(v3+1)(v3-1) = (v3)^2 - 1^2 = 3-1 = 2.' },
  { id: 'math80', year: 2024, topic: 'Differentiation', difficulty: 'medium', question: 'Find dy/dx if y = 3x^2 + 5x - 2.', options: ['A: 6x + 5', 'B: 3x + 5', 'C: 6x - 2', 'D: 3x^2 + 5'], answer: 'A', explanation: 'dy/dx = d/dx(3x^2) + d/dx(5x) - d/dx(2) = 6x + 5 - 0 = 6x + 5.' },
  { id: 'math81', year: 2023, topic: 'Differentiation', difficulty: 'hard', question: 'If y = (2x+1)^3, find dy/dx.', options: ['A: 3(2x+1)^2', 'B: 6(2x+1)^2', 'C: 2(2x+1)^3', 'D: 3(2x+1)^3'], answer: 'B', explanation: 'Using chain rule: dy/dx = 3(2x+1)^2 x 2 = 6(2x+1)^2.' },
  { id: 'math82', year: 2022, topic: 'Differentiation', difficulty: 'medium', question: 'If y = 1/x, find dy/dx.', options: ['A: 1/x^2', 'B: -1/x^2', 'C: 1/x', 'D: -1/x'], answer: 'B', explanation: 'y = x^(-1). dy/dx = -1 x x^(-2) = -1/x^2.' },
  { id: 'math83', year: 2023, topic: 'Sequences & Series', difficulty: 'hard', question: 'Find the sum of the first 8 terms of AP: 2, 5, 8, 11...', options: ['A: 92', 'B: 100', 'C: 108', 'D: 116'], answer: 'B', explanation: 'a=2, d=3. S_8 = n/2[2a+(n-1)d] = 8/2[4+21] = 4x25 = 100.' },
  { id: 'math84', year: 2020, topic: 'Logarithms', difficulty: 'hard', question: 'If log_2 (x+1) = 3, find x.', options: ['A: 5', 'B: 7', 'C: 8', 'D: 9'], answer: 'B', explanation: 'log_2 (x+1) = 3, so x+1 = 2^3 = 8, x = 7.' },
  { id: 'math85', year: 2021, topic: 'Mensuration', difficulty: 'medium', question: 'Area of a trapezium with parallel sides 8 cm and 12 cm, height 5 cm.', options: ['A: 40 cm^2', 'B: 50 cm^2', 'C: 60 cm^2', 'D: 80 cm^2'], answer: 'B', explanation: 'Area = 1/2(a+b)h = 1/2(8+12)x5 = 1/2x20x5 = 50 cm^2.' },
  { id: 'math86', year: 2020, topic: 'Algebra', difficulty: 'hard', question: 'Simplify: (x^2 - 9)/(x - 3).', options: ['A: x+3', 'B: x-3', 'C: x+9', 'D: x-9'], answer: 'A', explanation: 'x^2 - 9 = (x-3)(x+3). Cancel (x-3): result = x+3.' },
  { id: 'math87', year: 2022, topic: 'Sets', difficulty: 'medium', question: 'If A = {a,b,c,d} and B = {c,d,e,f}, find A - B.', options: ['A: {a,b}', 'B: {c,d}', 'C: {e,f}', 'D: {a,b,e,f}'], answer: 'A', explanation: 'A - B contains elements in A but not in B: {a,b}.' },
  { id: 'math88', year: 2023, topic: 'Matrices', difficulty: 'medium', question: 'Find the transpose of [[1,2,3],[4,5,6]].', options: ['A: [[1,4],[2,5],[3,6]]', 'B: [[1,2],[3,4],[5,6]]', 'C: [[1,4],[5,2],[3,6]]', 'D: [[6,5],[4,3],[2,1]]'], answer: 'A', explanation: 'Transpose swaps rows and columns. Row 1 becomes column 1, row 2 becomes column 2.' },
  { id: 'math89', year: 2020, topic: 'Variation', difficulty: 'hard', question: 'y varies partly as x and partly as x^2. If y = 12 when x = 2, and y = 36 when x = 3, find y when x = 4.', options: ['A: 72', 'B: 64', 'C: 80', 'D: 48'], answer: 'A', explanation: 'y = ax + bx^2. 12 = 2a+4b, 36 = 3a+9b. Solving: a=2, b=2. y = 2(4)+2(16) = 8+32 = 40. Wait, recalc: 2a+4b=12, 3a+9b=36. Multiply first by 3: 6a+12b=36. Second by 2: 6a+18b=72. Subtract: 6b=36, b=6. Then 2a+24=12, 2a=-12, a=-6. y = -6x + 6x^2. At x=4: -24+96=72.' },
  { id: 'math90', year: 2024, topic: 'Differentiation', difficulty: 'medium', question: 'Find the gradient of y = 2x^2 - 3x + 1 at x = 2.', options: ['A: 3', 'B: 5', 'C: 7', 'D: 9'], answer: 'B', explanation: 'dy/dx = 4x - 3. At x=2: gradient = 4(2) - 3 = 8 - 3 = 5.' },
  { id: 'math91', year: 2021, topic: 'Algebra', difficulty: 'hard', question: 'Solve simultaneously: x + y = 7, x - y = 1.', options: ['A: x=4, y=3', 'B: x=3, y=4', 'C: x=5, y=2', 'D: x=2, y=5'], answer: 'A', explanation: 'Add: 2x = 8, x = 4. Then 4 - y = 1, y = 3.' },
  { id: 'math92', year: 2021, topic: 'Geometry', difficulty: 'medium', question: 'Arc length of sector with radius 7 cm and angle 60 degrees. (Pi = 22/7)', options: ['A: 7.33 cm', 'B: 14.67 cm', 'C: 22 cm', 'D: 44 cm'], answer: 'A', explanation: 'Arc = (theta/360) x 2 pi r = (60/360) x 2 x 22/7 x 7 = (1/6) x 44 = 7.33 cm.' },
  { id: 'math93', year: 2022, topic: 'Trigonometry', difficulty: 'hard', question: 'Solve: 2 sin x - 1 = 0 for 0 <= x <= 90.', options: ['A: 30', 'B: 45', 'C: 60', 'D: 90'], answer: 'A', explanation: '2 sin x = 1, sin x = 1/2, so x = 30 degrees (in the given range).' },
  { id: 'math94', year: 2024, topic: 'Statistics', difficulty: 'medium', question: 'Mean of 5 numbers is 12. If one number 8 is removed, what is the new mean?', options: ['A: 12', 'B: 13', 'C: 14', 'D: 15'], answer: 'B', explanation: 'Sum of 5 = 60. Remove 8: sum = 52, count = 4. New mean = 52/4 = 13.' },
  { id: 'math95', year: 2023, topic: 'Probability', difficulty: 'hard', question: 'A box has 3 defective and 7 good items. Two picked without replacement. P(both good)?', options: ['A: 7/15', 'B: 7/10', 'C: 3/10', 'D: 1/3'], answer: 'A', explanation: 'P(first good) = 7/10. P(second good|first good) = 6/9 = 2/3. P = 7/10 x 2/3 = 14/30 = 7/15.' },
  { id: 'math96', year: 2024, topic: 'Surds', difficulty: 'easy', question: 'Simplify v9.', options: ['A: 2', 'B: 3', 'C: 4', 'D: 81'], answer: 'B', explanation: 'v9 = 3 because 3^2 = 9.' },
  { id: 'math97', year: 2020, topic: 'Number Bases', difficulty: 'medium', question: 'Convert 35_10 to binary.', options: ['A: 100011_2', 'B: 100101_2', 'C: 110011_2', 'D: 1000111_2'], answer: 'A', explanation: '35/2=17r1, 17/2=8r1, 8/2=4r0, 4/2=2r0, 2/2=1r0, 1/2=0r1. Reading remainders backwards: 100011.' },
  { id: 'math98', year: 2021, topic: 'Mensuration', difficulty: 'medium', question: 'Volume of a cylinder with radius 3 cm and height 10 cm. (Pi = 3.14)', options: ['A: 188.4 cm^3', 'B: 282.6 cm^3', 'C: 94.2 cm^3', 'D: 376.8 cm^3'], answer: 'B', explanation: 'V = pi r^2 h = 3.14 x 9 x 10 = 3.14 x 90 = 282.6 cm^3.' },
  { id: 'math99', year: 2020, topic: 'Sequences & Series', difficulty: 'easy', question: 'Find the 5th term of AP: 10, 7, 4, 1...', options: ['A: -2', 'B: -5', 'C: 2', 'D: 5'], answer: 'B', explanation: 'a=10, d=-3. T_5 = 10 + 4(-3) = 10 - 12 = -2.' },
  { id: 'math100', year: 2024, topic: 'Logarithms', difficulty: 'hard', question: 'If log_10 2 = 0.3010, find log_10 8.', options: ['A: 0.6020', 'B: 0.9030', 'C: 0.9542', 'D: 1.2040'], answer: 'B', explanation: 'log_10 8 = log_10 2^3 = 3 x log_10 2 = 3 x 0.3010 = 0.9030.' },
  { id: 'math101', year: 2023, topic: 'Algebra', difficulty: 'medium', question: 'Given f(x) = 3x - 4, find f(2).', options: ['A: -2', 'B: 2', 'C: 4', 'D: 6'], answer: 'B', explanation: 'f(2) = 3(2) - 4 = 6 - 4 = 2.' },
  { id: 'math102', year: 2022, topic: 'Geometry', difficulty: 'medium', question: 'Angle at the centre of a circle is twice the angle at the circumference. This is known as:', options: ['A: Pythagoras theorem', 'B: Circle theorem', 'C: Tangent theorem', 'D: Chord theorem'], answer: 'B', explanation: 'This is a fundamental circle theorem: the angle subtended at the centre is twice that at the circumference.' },
  { id: 'math103', year: 2021, topic: 'Trigonometry', difficulty: 'medium', question: 'If cos x = 0.5, find x (0 <= x <= 90).', options: ['A: 30', 'B: 45', 'C: 60', 'D: 90'], answer: 'C', explanation: 'cos 60 = 0.5. Therefore x = 60 degrees.' },
  { id: 'math104', year: 2024, topic: 'Matrices', difficulty: 'medium', question: 'Two matrices A and B are equal if they have the same:', options: ['A: Determinant', 'B: Order and corresponding elements', 'C: Trace', 'D: Number of rows'], answer: 'B', explanation: 'For matrices to be equal, they must have the same order (dimensions) and equal corresponding elements.' },
  { id: 'math105', year: 2023, topic: 'Sets', difficulty: 'easy', question: 'The empty set is denoted by:', options: ['A: {0}', 'B: { } or O/ (phi)', 'C: {1}', 'D: {empty}'], answer: 'B', explanation: 'The empty set (null set) is denoted by { } or the symbol O/ (phi). {0} is not empty as it contains 0.' }
]

// PHYSICS
const physicsQuestions = [
  { id: 'phy26', year: 2024, topic: 'Mechanics', difficulty: 'medium', question: 'A force of 30 N acts on a body of mass 6 kg for 4 s. If the body starts from rest, find its final velocity.', options: ['A: 5 m/s', 'B: 10 m/s', 'C: 20 m/s', 'D: 30 m/s'], answer: 'C', explanation: 'F = ma, a = 30/6 = 5 m/s^2. v = u + at = 0 + 5x4 = 20 m/s.' },
  { id: 'phy27', year: 2024, topic: 'Waves & Optics', difficulty: 'medium', question: 'A wave has frequency 200 Hz and wavelength 0.5 m. Find its speed.', options: ['A: 50 m/s', 'B: 100 m/s', 'C: 200 m/s', 'D: 400 m/s'], answer: 'B', explanation: 'v = f(lambda) = 200 x 0.5 = 100 m/s.' },
  { id: 'phy28', year: 2024, topic: 'Electricity', difficulty: 'hard', question: 'Three resistors 4, 6, and 12 Ohms in parallel. Total resistance?', options: ['A: 2 Ohm', 'B: 3 Ohm', 'C: 4 Ohm', 'D: 22 Ohm'], answer: 'A', explanation: '1/R = 1/4+1/6+1/12 = 3/12+2/12+1/12 = 6/12 = 1/2. R = 2 Ohm.' },
  { id: 'phy29', year: 2024, topic: 'Thermodynamics', difficulty: 'medium', question: 'Ice at 0 C is melting. Which process describes this?', options: ['A: Fusion', 'B: Vaporisation', 'C: Sublimation', 'D: Condensation'], answer: 'A', explanation: 'Melting (fusion) is the change from solid to liquid at constant temperature.' },
  { id: 'phy30', year: 2024, topic: 'Modern Physics', difficulty: 'medium', question: 'The energy of a photon is directly proportional to its:', options: ['A: Wavelength', 'B: Frequency', 'C: Speed', 'D: Amplitude'], answer: 'B', explanation: 'E = hf, so energy is directly proportional to frequency. It is inversely proportional to wavelength.' },
  { id: 'phy31', year: 2024, topic: 'Measurements & Units', difficulty: 'easy', question: 'The SI unit of force is:', options: ['A: Joule', 'B: Newton', 'C: Watt', 'D: Pascal'], answer: 'B', explanation: 'The Newton (N) is the SI unit of force. Joule = energy, Watt = power, Pascal = pressure.' },
  { id: 'phy32', year: 2024, topic: 'Motion', difficulty: 'medium', question: 'A car decelerates from 25 m/s to 5 m/s in 4 s. Deceleration?', options: ['A: 2 m/s^2', 'B: 5 m/s^2', 'C: 7.5 m/s^2', 'D: 20 m/s^2'], answer: 'B', explanation: 'a = (v-u)/t = (5-25)/4 = -20/4 = -5 m/s^2. Deceleration = 5 m/s^2.' },
  { id: 'phy33', year: 2024, topic: 'Simple Harmonic Motion', difficulty: 'hard', question: 'A pendulum has length 1.0 m. Find its period. (g = 10 m/s^2, pi^2 ~ 10)', options: ['A: 1.0 s', 'B: 1.5 s', 'C: 2.0 s', 'D: 3.14 s'], answer: 'C', explanation: 'T = 2pi v(L/g) = 2pi v(1/10) = 2pi / v10 ~ 2 x 3.14/3.16 ~ 2.0 s.' },
  { id: 'phy34', year: 2024, topic: 'Acoustics', difficulty: 'medium', question: 'The loudness of sound depends on:', options: ['A: Frequency', 'B: Amplitude', 'C: Wavelength', 'D: Speed'], answer: 'B', explanation: 'Loudness depends on amplitude of the sound wave. Larger amplitude = louder sound.' },
  { id: 'phy35', year: 2024, topic: 'Elasticity', difficulty: 'medium', question: 'A wire of length 2 m extends by 1 mm under a load. Strain = ?', options: ['A: 5x10^-4', 'B: 5x10^-3', 'C: 0.5', 'D: 0.05'], answer: 'A', explanation: 'Strain = extension/original length = 0.001/2 = 5x10^-4.' },
  { id: 'phy36', year: 2024, topic: 'Electromagnetism', difficulty: 'medium', question: 'The direction of induced current is given by:', options: ['A: Flemings left-hand rule', 'B: Flemings right-hand rule', 'C: Right-hand grip rule', 'D: Amperes rule'], answer: 'B', explanation: 'Flemings right-hand rule gives the direction of induced current in a generator.' },
  { id: 'phy37', year: 2024, topic: 'Magnetism', difficulty: 'easy', question: 'Which material is ferromagnetic?', options: ['A: Copper', 'B: Aluminium', 'C: Iron', 'D: Wood'], answer: 'C', explanation: 'Iron is ferromagnetic and can be permanently magnetized. Copper and aluminium are paramagnetic.' },
  { id: 'phy38', year: 2024, topic: 'Nuclear Physics', difficulty: 'hard', question: 'In a nuclear fission reaction, U-235 absorbs a neutron and splits into Ba-141 and Kr-92 plus:', options: ['A: 1 neutron', 'B: 2 neutrons', 'C: 3 neutrons', 'D: 4 neutrons'], answer: 'C', explanation: 'U-235 + n -> Ba-141 + Kr-92 + 3n. The 3 neutrons can trigger further fission in a chain reaction.' },
  { id: 'phy39', year: 2024, topic: 'Hydrostatics', difficulty: 'medium', question: 'Pressure at depth 10 m in water. (density = 1000 kg/m^3, g = 10 m/s^2)', options: ['A: 10^4 Pa', 'B: 10^5 Pa', 'C: 10^6 Pa', 'D: 10^7 Pa'], answer: 'B', explanation: 'P = hdg = 10 x 1000 x 10 = 100,000 = 10^5 Pa.' },
  { id: 'phy40', year: 2023, topic: 'Mechanics', difficulty: 'medium', question: 'A pulley system with 4 ropes supporting a load has a mechanical advantage of:', options: ['A: 1', 'B: 2', 'C: 4', 'D: 8'], answer: 'C', explanation: 'For an ideal pulley system, MA = number of supporting ropes = 4.' },
  { id: 'phy41', year: 2023, topic: 'Waves & Optics', difficulty: 'hard', question: 'Light enters glass from air (n = 1.5). If incidence angle = 45 deg, find refraction angle. (sin 45 = 0.707)', options: ['A: 22 deg', 'B: 28 deg', 'C: 32 deg', 'D: 45 deg'], answer: 'B', explanation: 'n = sin i / sin r, 1.5 = 0.707/sin r, sin r = 0.471, r ~ 28 degrees.' },
  { id: 'phy42', year: 2023, topic: 'Electricity', difficulty: 'medium', question: 'Power dissipated in a 20 Ohm resistor with 5 A current?', options: ['A: 100 W', 'B: 250 W', 'C: 500 W', 'D: 1000 W'], answer: 'C', explanation: 'P = I^2 R = 25 x 20 = 500 W.' },
  { id: 'phy43', year: 2023, topic: 'Thermodynamics', difficulty: 'hard', question: 'A Carnot engine operates between 400 K and 300 K. Maximum efficiency?', options: ['A: 25%', 'B: 33%', 'C: 50%', 'D: 75%'], answer: 'A', explanation: 'Efficiency = (T_h - T_c)/T_h = (400-300)/400 = 100/400 = 0.25 = 25%.' },
  { id: 'phy44', year: 2023, topic: 'Modern Physics', difficulty: 'hard', question: 'Threshold frequency of a metal is 4x10^14 Hz. Work function? (h = 6.6x10^-34 Js)', options: ['A: 2.64x10^-19 J', 'B: 6.6x10^-19 J', 'C: 1.32x10^-19 J', 'D: 3.3x10^-19 J'], answer: 'A', explanation: 'W = hf_0 = 6.6x10^-34 x 4x10^14 = 2.64x10^-19 J.' },
  { id: 'phy45', year: 2023, topic: 'Measurements & Units', difficulty: 'easy', question: 'Which is a scalar quantity?', options: ['A: Force', 'B: Velocity', 'C: Temperature', 'D: Acceleration'], answer: 'C', explanation: 'Temperature has magnitude only (scalar). Force, velocity, and acceleration are vectors with direction.' },
  { id: 'phy46', year: 2023, topic: 'Motion', difficulty: 'hard', question: 'A stone is dropped from a height of 80 m. Time to hit ground? (g = 10 m/s^2)', options: ['A: 2 s', 'B: 3 s', 'C: 4 s', 'D: 5 s'], answer: 'C', explanation: 's = ut + 1/2 gt^2, 80 = 0 + 1/2 x 10 x t^2 = 5t^2, t^2 = 16, t = 4 s.' },
  { id: 'phy47', year: 2023, topic: 'Simple Harmonic Motion', difficulty: 'medium', question: 'Maximum velocity of a body in SHM occurs at:', options: ['A: Extreme position', 'B: Equilibrium position', 'C: Midpoint between extreme and equilibrium', 'D: One-third of amplitude'], answer: 'B', explanation: 'In SHM, velocity is maximum at the equilibrium position where displacement is zero.' },
  { id: 'phy48', year: 2023, topic: 'Acoustics', difficulty: 'medium', question: 'An echo is heard 0.5 s after sound production. Distance of reflecting surface? (Speed of sound = 340 m/s)', options: ['A: 85 m', 'B: 170 m', 'C: 340 m', 'D: 680 m'], answer: 'A', explanation: 'Total distance = v x t = 340 x 0.5 = 170 m (to and from). Distance to surface = 170/2 = 85 m.' },
  { id: 'phy49', year: 2023, topic: 'Elasticity', difficulty: 'hard', question: 'A spring constant k = 500 N/m is stretched 0.1 m. Elastic potential energy?', options: ['A: 2.5 J', 'B: 5 J', 'C: 25 J', 'D: 50 J'], answer: 'A', explanation: 'EPE = 1/2 kx^2 = 1/2 x 500 x 0.01 = 2.5 J.' },
  { id: 'phy50', year: 2023, topic: 'Electromagnetism', difficulty: 'medium', question: 'The force on a current-carrying conductor in a magnetic field is given by:', options: ['A: F = BIL', 'B: F = BIL sin theta', 'C: F = BL/I', 'D: F = B/IL'], answer: 'B', explanation: 'F = BIL sin theta, where theta is the angle between the conductor and the magnetic field.' },
  { id: 'phy51', year: 2023, topic: 'Magnetism', difficulty: 'medium', question: 'The Earths magnetic field is believed to be due to:', options: ['A: Iron core rotation', 'B: Electric currents in the core', 'C: Solar wind', 'D: Permanent magnets'], answer: 'B', explanation: 'Earths magnetic field is believed to originate from electric currents in the molten iron outer core (dynamo effect).' },
  { id: 'phy52', year: 2023, topic: 'Nuclear Physics', difficulty: 'medium', question: 'Which particle has the greatest penetrating power?', options: ['A: Alpha', 'B: Beta', 'C: Gamma', 'D: Proton'], answer: 'C', explanation: 'Gamma rays have the greatest penetrating power. Alpha has least, beta is intermediate.' },
  { id: 'phy53', year: 2023, topic: 'Hydrostatics', difficulty: 'medium', question: 'Upthrust on a body immersed in fluid equals:', options: ['A: Weight of the body', 'B: Weight of fluid displaced', 'C: Volume of the body', 'D: Density of the fluid'], answer: 'B', explanation: 'Archimedes principle: upthrust equals the weight of the fluid displaced by the body.' },
  { id: 'phy54', year: 2022, topic: 'Mechanics', difficulty: 'hard', question: 'Moments: a 50 N force at 0.3 m from pivot. Perpendicular distance? Moment?', options: ['A: 10 Nm', 'B: 15 Nm', 'C: 20 Nm', 'D: 150 Nm'], answer: 'B', explanation: 'Moment = F x d = 50 x 0.3 = 15 Nm.' },
  { id: 'phy55', year: 2022, topic: 'Waves & Optics', difficulty: 'easy', question: 'Which electromagnetic wave has the longest wavelength?', options: ['A: X-ray', 'B: Ultraviolet', 'C: Radio wave', 'D: Gamma ray'], answer: 'C', explanation: 'Radio waves have the longest wavelength in the EM spectrum. Gamma rays have the shortest.' },
  { id: 'phy56', year: 2022, topic: 'Electricity', difficulty: 'easy', question: 'Ohms law states that V = I x R. V is measured in:', options: ['A: Amperes', 'B: Volts', 'C: Ohms', 'D: Watts'], answer: 'B', explanation: 'V is voltage measured in Volts. I is current (Amperes), R is resistance (Ohms).' },
  { id: 'phy57', year: 2022, topic: 'Thermodynamics', difficulty: 'medium', question: 'Conversion of gas to liquid is called:', options: ['A: Melting', 'B: Freezing', 'C: Condensation', 'D: Sublimation'], answer: 'C', explanation: 'Condensation is the change from gaseous to liquid state.' },
  { id: 'phy58', year: 2022, topic: 'Modern Physics', difficulty: 'medium', question: 'The atomic number of an element is the number of:', options: ['A: Neutrons', 'B: Protons', 'C: Electrons plus neutrons', 'D: Nucleons'], answer: 'B', explanation: 'Atomic number (Z) is the number of protons in the nucleus of an atom.' },
  { id: 'phy59', year: 2022, topic: 'Measurements & Units', difficulty: 'medium', question: '1 kWh is equal to:', options: ['A: 3.6x10^3 J', 'B: 3.6x10^6 J', 'C: 3.6x10^9 J', 'D: 3600 J'], answer: 'B', explanation: '1 kWh = 1000 W x 3600 s = 3.6x10^6 J.' },
  { id: 'phy60', year: 2022, topic: 'Motion', difficulty: 'medium', question: 'A cyclist travels 30 km north then 40 km east. Displacement?', options: ['A: 50 km', 'B: 70 km', 'C: 10 km', 'D: 140 km'], answer: 'A', explanation: 'Displacement = v(30^2+40^2) = v(900+1600) = v2500 = 50 km.' },
  { id: 'phy61', year: 2022, topic: 'Simple Harmonic Motion', difficulty: 'hard', question: 'A body in SHM has amplitude 0.1 m and frequency 2 Hz. Maximum acceleration?', options: ['A: 0.4 pi^2 m/s^2', 'B: 1.6 pi^2 m/s^2', 'C: 4 pi^2 m/s^2', 'D: 8 pi^2 m/s^2'], answer: 'B', explanation: 'a_max = w^2 A. w = 2pi f = 4pi. a_max = (4pi)^2 x 0.1 = 16pi^2 x 0.1 = 1.6pi^2 m/s^2.' },
  { id: 'phy62', year: 2022, topic: 'Acoustics', difficulty: 'medium', question: 'Beats are produced when two waves of slightly different _____ interfere.', options: ['A: Amplitudes', 'B: Frequencies', 'C: Wavelengths', 'D: Speeds'], answer: 'B', explanation: 'Beats occur when two sound waves of nearly equal frequencies interfere, producing periodic variations in loudness.' },
  { id: 'phy63', year: 2022, topic: 'Elasticity', difficulty: 'easy', question: 'The ability of a material to return to its original shape after deformation is:', options: ['A: Plasticity', 'B: Elasticity', 'C: Ductility', 'D: Malleability'], answer: 'B', explanation: 'Elasticity is the property of a material to regain its original shape after removing the deforming force.' },
  { id: 'phy64', year: 2022, topic: 'Electromagnetism', difficulty: 'hard', question: 'A transformer with 200 primary turns and 1000 secondary turns has input 240 V. Output voltage?', options: ['A: 48 V', 'B: 240 V', 'C: 1200 V', 'D: 2000 V'], answer: 'C', explanation: 'V_s/V_p = N_s/N_p, V_s = 240 x 1000/200 = 240 x 5 = 1200 V.' },
  { id: 'phy65', year: 2022, topic: 'Magnetism', difficulty: 'hard', question: 'Magnetic flux density is measured in:', options: ['A: Weber', 'B: Tesla', 'C: Henry', 'D: Gauss'], answer: 'B', explanation: 'The SI unit of magnetic flux density (B) is Tesla (T). Weber = magnetic flux.' },
  { id: 'phy66', year: 2022, topic: 'Nuclear Physics', difficulty: 'hard', question: 'Half-life of a radioactive substance is 10 years. After 30 years, fraction remaining?', options: ['A: 1/2', 'B: 1/4', 'C: 1/8', 'D: 1/16'], answer: 'C', explanation: 'After 3 half-lives (30/10=3): fraction = (1/2)^3 = 1/8.' },
  { id: 'phy67', year: 2022, topic: 'Hydrostatics', difficulty: 'hard', question: 'A block of density 800 kg/m^3 floats in water (1000 kg/m^3). Fraction submerged?', options: ['A: 0.2', 'B: 0.5', 'C: 0.8', 'D: 1.0'], answer: 'C', explanation: 'Fraction submerged = density of object/density of fluid = 800/1000 = 0.8.' },
  { id: 'phy68', year: 2021, topic: 'Mechanics', difficulty: 'hard', question: 'A ball of mass 0.5 kg moving at 10 m/s collides inelastically with a stationary ball of mass 1.5 kg. Common velocity?', options: ['A: 2.5 m/s', 'B: 5 m/s', 'C: 7.5 m/s', 'D: 10 m/s'], answer: 'A', explanation: 'Momentum conserved: 0.5x10 = (0.5+1.5)v, 5 = 2v, v = 2.5 m/s.' },
  { id: 'phy69', year: 2021, topic: 'Waves & Optics', difficulty: 'medium', question: 'Critical angle for light traveling from glass (n=1.5) to air?', options: ['A: 30 deg', 'B: 41.8 deg', 'C: 45 deg', 'D: 60 deg'], answer: 'B', explanation: 'sin C = 1/n = 1/1.5 = 0.667, C = sin^-1(0.667) ~ 41.8 degrees.' },
  { id: 'phy70', year: 2021, topic: 'Electricity', difficulty: 'medium', question: 'A 12 V battery delivers 2 A to a lamp. Resistance of the lamp?', options: ['A: 4 Ohm', 'B: 6 Ohm', 'C: 12 Ohm', 'D: 24 Ohm'], answer: 'B', explanation: 'R = V/I = 12/2 = 6 Ohm.' },
  { id: 'phy71', year: 2021, topic: 'Thermodynamics', difficulty: 'easy', question: 'Temperature of melting ice on Celsius scale:', options: ['A: -273 C', 'B: 0 C', 'C: 100 C', 'D: 273 C'], answer: 'B', explanation: 'Ice melts at 0 degrees Celsius at standard atmospheric pressure.' },
  { id: 'phy72', year: 2021, topic: 'Modern Physics', difficulty: 'medium', question: 'In the photoelectric effect, the stopping potential depends on:', options: ['A: Intensity of light', 'B: Frequency of light', 'C: Work function only', 'D: Area of metal'], answer: 'B', explanation: 'Stopping potential depends on the frequency (or energy) of incident photons, not on intensity.' },
  { id: 'phy73', year: 2021, topic: 'Measurements & Units', difficulty: 'medium', question: 'The dimension of pressure is:', options: ['A: ML^-1T^-2', 'B: MLT^-2', 'C: ML^2T^-3', 'D: ML^-2T^-2'], answer: 'A', explanation: 'Pressure = Force/Area = (MLT^-2)/L^2 = ML^-1T^-2.' },
  { id: 'phy74', year: 2021, topic: 'Motion', difficulty: 'hard', question: 'A projectile is launched at 30 degrees with speed 40 m/s. Maximum height? (g=10)', options: ['A: 10 m', 'B: 20 m', 'C: 30 m', 'D: 40 m'], answer: 'B', explanation: 'u_y = 40 sin 30 = 20 m/s. H = u_y^2/2g = 400/20 = 20 m.' },
  { id: 'phy75', year: 2021, topic: 'Simple Harmonic Motion', difficulty: 'medium', question: 'The period of a mass-spring system depends on:', options: ['A: Amplitude', 'B: Mass and spring constant', 'C: Gravity', 'D: Initial displacement'], answer: 'B', explanation: 'T = 2pi v(m/k). Period depends on mass and spring constant, not on amplitude or gravity.' },
  { id: 'phy76', year: 2021, topic: 'Acoustics', difficulty: 'hard', question: 'Fundamental frequency of a string 1 m long, wave speed 200 m/s:', options: ['A: 50 Hz', 'B: 100 Hz', 'C: 200 Hz', 'D: 400 Hz'], answer: 'B', explanation: 'Fundamental: f = v/2L = 200/(2x1) = 100 Hz.' },
  { id: 'phy77', year: 2021, topic: 'Elasticity', difficulty: 'medium', question: 'Youngs modulus has the same unit as:', options: ['A: Pressure', 'B: Force', 'C: Strain', 'D: Energy'], answer: 'A', explanation: 'Youngs modulus = stress/strain. Stress = Force/Area (unit: Pa). Strain is dimensionless. So Youngs modulus has unit of pressure (Pa).' },
  { id: 'phy78', year: 2021, topic: 'Electromagnetism', difficulty: 'medium', question: 'The direction of magnetic field around a current-carrying wire is given by:', options: ['A: Newtons law', 'B: Right-hand grip rule', 'C: Left-hand rule', 'D: Faradays law'], answer: 'B', explanation: 'The right-hand grip rule: thumb points in current direction, fingers curl in magnetic field direction.' },
  { id: 'phy79', year: 2021, topic: 'Magnetism', difficulty: 'medium', question: 'A material that is repelled by a magnet is called:', options: ['A: Ferromagnetic', 'B: Paramagnetic', 'C: Diamagnetic', 'D: Electromagnetic'], answer: 'C', explanation: 'Diamagnetic materials are repelled by magnets. Ferromagnetic and paramagnetic materials are attracted.' },
  { id: 'phy80', year: 2021, topic: 'Nuclear Physics', difficulty: 'medium', question: 'Beta decay involves the emission of:', options: ['A: Helium nucleus', 'B: Electron', 'C: Photon', 'D: Neutron'], answer: 'B', explanation: 'Beta decay involves the emission of an electron (beta-minus) or positron (beta-plus) from the nucleus.' },
  { id: 'phy81', year: 2020, topic: 'Mechanics', difficulty: 'easy', question: 'Mass of an object on Earth is 60 kg. Its mass on the Moon is:', options: ['A: 10 kg', 'B: 60 kg', 'C: 360 kg', 'D: 0 kg'], answer: 'B', explanation: 'Mass is constant everywhere. Weight changes due to gravity, but mass stays the same.' },
  { id: 'phy82', year: 2020, topic: 'Waves & Optics', difficulty: 'hard', question: 'In a Youngs double-slit experiment, fringe separation increases when:', options: ['A: Slit separation increases', 'B: Wavelength increases', 'C: Distance to screen decreases', 'D: Slit width increases'], answer: 'B', explanation: 'Fringe separation = (lambda x D)/d. It increases with wavelength (lambda) and screen distance (D), decreases with slit separation (d).' },
  { id: 'phy83', year: 2020, topic: 'Electricity', difficulty: 'hard', question: 'A 2 uF capacitor is charged to 100 V. Energy stored?', options: ['A: 0.01 J', 'B: 0.02 J', 'C: 0.1 J', 'D: 1 J'], answer: 'A', explanation: 'E = 1/2 CV^2 = 1/2 x 2x10^-6 x 10000 = 1x10^-6 x 10000 = 0.01 J.' },
  { id: 'phy84', year: 2020, topic: 'Thermodynamics', difficulty: 'medium', question: 'Heat transfer by electromagnetic waves is called:', options: ['A: Conduction', 'B: Convection', 'C: Radiation', 'D: Evaporation'], answer: 'C', explanation: 'Radiation is heat transfer via electromagnetic waves without requiring a medium.' },
  { id: 'phy85', year: 2020, topic: 'Modern Physics', difficulty: 'hard', question: 'Einsteins mass-energy equivalence is given by:', options: ['A: E = mc', 'B: E = mc^2', 'C: E = hf', 'D: E = 1/2 mv^2'], answer: 'B', explanation: 'Einsteins equation E = mc^2 states that mass and energy are interchangeable.' },
  { id: 'phy86', year: 2020, topic: 'Measurements & Units', difficulty: 'hard', question: 'The vernier caliper reading is 2.35 cm. The smallest division is:', options: ['A: 1 cm', 'B: 0.1 cm', 'C: 0.05 cm', 'D: 0.01 cm'], answer: 'D', explanation: 'A standard vernier caliper measures to 0.01 cm (0.1 mm) precision.' },
  { id: 'phy87', year: 2020, topic: 'Motion', difficulty: 'easy', question: 'Distance-time graph for uniform speed is a:', options: ['A: Curved line', 'B: Straight line through origin', 'C: Horizontal line', 'D: Vertical line'], answer: 'B', explanation: 'Uniform speed gives a constant rate of change of distance, producing a straight line.' },
  { id: 'phy88', year: 2020, topic: 'Simple Harmonic Motion', difficulty: 'easy', question: 'In SHM, acceleration is proportional to:', options: ['A: Velocity', 'B: Displacement', 'C: Time', 'D: Amplitude'], answer: 'B', explanation: 'In SHM, a = -w^2 x, acceleration is proportional to displacement and opposite in direction.' },
  { id: 'phy89', year: 2020, topic: 'Acoustics', difficulty: 'medium', question: 'The speed of sound is greatest in:', options: ['A: Vacuum', 'B: Air', 'C: Water', 'D: Steel'], answer: 'D', explanation: 'Sound travels fastest in solids (steel), slower in liquids (water), and slowest in gases (air). Cannot travel in vacuum.' },
  { id: 'phy90', year: 2020, topic: 'Elasticity', difficulty: 'hard', question: 'A wire of cross-sectional area 2x10^-6 m^2 experiences stress of 4x10^7 Pa. Force applied?', options: ['A: 20 N', 'B: 40 N', 'C: 80 N', 'D: 200 N'], answer: 'C', explanation: 'Stress = Force/Area. F = Stress x Area = 4x10^7 x 2x10^-6 = 80 N.' },
  { id: 'phy91', year: 2020, topic: 'Electromagnetism', difficulty: 'medium', question: 'Faradays law states that induced EMF is proportional to:', options: ['A: Magnetic field', 'B: Rate of change of flux', 'C: Current', 'D: Resistance'], answer: 'B', explanation: 'Faradays law: induced EMF is proportional to the rate of change of magnetic flux linkage.' },
  { id: 'phy92', year: 2020, topic: 'Magnetism', difficulty: 'medium', question: 'The magnetic field inside a long solenoid is:', options: ['A: Zero', 'B: Uniform', 'C: Varying linearly', 'D: Maximum at ends'], answer: 'B', explanation: 'The magnetic field inside a long solenoid is nearly uniform (constant magnitude and direction).' },
  { id: 'phy93', year: 2020, topic: 'Nuclear Physics', difficulty: 'easy', question: 'Which radiation has no charge?', options: ['A: Alpha', 'B: Beta', 'C: Gamma', 'D: All have charge'], answer: 'C', explanation: 'Gamma rays are electromagnetic radiation with no charge. Alpha (positive) and beta (negative) are charged particles.' },
  { id: 'phy94', year: 2024, topic: 'Hydrostatics', difficulty: 'medium', question: 'A hydraulic press has piston areas 0.01 m^2 and 0.5 m^2. Force on small piston = 100 N. Force on large piston?', options: ['A: 500 N', 'B: 1000 N', 'C: 5000 N', 'D: 10000 N'], answer: 'C', explanation: 'P = F1/A1 = F2/A2. F2 = F1 x A2/A1 = 100 x 0.5/0.01 = 100 x 50 = 5000 N.' },
  { id: 'phy95', year: 2023, topic: 'Electromagnetism', difficulty: 'easy', question: 'The unit of magnetic flux is:', options: ['A: Tesla', 'B: Weber', 'C: Henry', 'D: Coulomb'], answer: 'B', explanation: 'Magnetic flux (phi) is measured in Webers (Wb). Tesla is magnetic flux density.' },
  { id: 'phy96', year: 2022, topic: 'Electricity', difficulty: 'medium', question: 'In a series circuit with 2 Ohm and 3 Ohm resistors, current = 2 A. Total voltage?', options: ['A: 4 V', 'B: 6 V', 'C: 10 V', 'D: 12 V'], answer: 'C', explanation: 'R_total = 2+3 = 5 Ohm. V = IR = 2 x 5 = 10 V.' },
  { id: 'phy97', year: 2021, topic: 'Mechanics', difficulty: 'medium', question: 'Work done lifting a 20 kg mass through 2 m. (g=10)', options: ['A: 40 J', 'B: 200 J', 'C: 400 J', 'D: 800 J'], answer: 'C', explanation: 'Work = Force x distance = mg x h = 20 x 10 x 2 = 400 J.' },
  { id: 'phy98', year: 2020, topic: 'Waves & Optics', difficulty: 'medium', question: 'A convex lens of focal length 10 cm forms a real image at 30 cm. Object distance?', options: ['A: 7.5 cm', 'B: 10 cm', 'C: 15 cm', 'D: 20 cm'], answer: 'C', explanation: '1/f = 1/u + 1/v. 1/10 = 1/u + 1/30, 1/u = 1/10 - 1/30 = 2/30, u = 15 cm.' },
  { id: 'phy99', year: 2024, topic: 'Electricity', difficulty: 'medium', question: 'Two cells of 1.5 V each in series give total EMF of:', options: ['A: 0.75 V', 'B: 1.5 V', 'C: 3 V', 'D: 4.5 V'], answer: 'C', explanation: 'Cells in series: total EMF = E1 + E2 = 1.5 + 1.5 = 3 V.' },
  { id: 'phy100', year: 2023, topic: 'Mechanics', difficulty: 'easy', question: 'A body at rest remains at rest unless acted upon by an external force. This is Newtons:', options: ['A: First law', 'B: Second law', 'C: Third law', 'D: Law of gravitation'], answer: 'A', explanation: 'Newtons first law (law of inertia): an object at rest stays at rest, in motion stays in motion unless acted on by a net force.' },
  { id: 'phy101', year: 2022, topic: 'Modern Physics', difficulty: 'hard', question: 'The de Broglie wavelength of an electron depends on its:', options: ['A: Charge', 'B: Momentum', 'C: Energy only', 'D: Mass only'], answer: 'B', explanation: 'lambda = h/p, where p is momentum. De Broglie wavelength is inversely proportional to momentum.' },
  { id: 'phy102', year: 2024, topic: 'Mechanics', difficulty: 'medium', question: 'A body of weight 80 N rests on a horizontal surface. If the coefficient of static friction is 0.4, the minimum force to move it is:', options: ['A: 20 N', 'B: 32 N', 'C: 40 N', 'D: 80 N'], answer: 'B', explanation: 'F_friction = mu x N = 0.4 x 80 = 32 N. Minimum force to overcome friction = 32 N.' },
  { id: 'phy103', year: 2023, topic: 'Waves & Optics', difficulty: 'medium', question: 'Colour of light is determined by its:', options: ['A: Amplitude', 'B: Frequency', 'C: Speed', 'D: Polarisation'], answer: 'B', explanation: 'The colour (or hue) of light is determined by its frequency (or wavelength).' },
  { id: 'phy104', year: 2020, topic: 'Motion', difficulty: 'medium', question: 'A ball is thrown vertically upward. At its highest point:', options: ['A: Velocity and acceleration are zero', 'B: Velocity is zero, acceleration is downward', 'C: Velocity is maximum', 'D: Acceleration is zero'], answer: 'B', explanation: 'At the highest point, velocity = 0, acceleration due to gravity (g) is still downward.' },
  { id: 'phy105', year: 2024, topic: 'Electricity', difficulty: 'hard', question: 'Kirchhoffs current law states that at a junction:', options: ['A: sum of currents entering = sum leaving', 'B: sum of voltages = 0', 'C: current is constant everywhere', 'D: power is conserved'], answer: 'A', explanation: 'Kirchhoffs current law (KCL): the algebraic sum of currents meeting at a junction is zero. Current in = current out.' }
];

